import ldap

def find_user_by_username(username, ldap_server, ldap_user, ldap_password):
    """
    Searches for a user in an LDAP directory by their username.

    Args:
        username: The username to search for.
        ldap_server: The LDAP server address.
        ldap_user: The LDAP username.
        ldap_password: The LDAP password.

    Returns:
        A dictionary containing the user information, or None if the user was not found.
    """

    # Create an LDAP connection
    conn = ldap.initialize(ldap_server)

    # Set the authentication credentials
    conn.simple_bind(ldap_user, ldap_password)

    # Search for the user by username
    result = conn.search(
        search_base="ou=Users,dc=example,dc=com",
        search_filter=f"uid={username}",
        search_scope=ldap.SCOPE_SUBTREE
    )

    # Close the LDAP connection
    conn.unbind()

    # Return the user information if found, or None otherwise
    if result:
        return ldap.parse_result(result[0])[1]
    else:
        return None